import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.DAK3ioSj.js";const u=JSON.parse('{"title":"ACE (Agentic Context Engineering)","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-ace.md","filePath":"radar/tech-ace.md"}'),n={name:"radar/tech-ace.md"};function l(i,t,d,s,h,g){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="ace-agentic-context-engineering" tabindex="-1">ACE (Agentic Context Engineering) <a class="header-anchor" href="#ace-agentic-context-engineering" aria-label="Permalink to &quot;ACE (Agentic Context Engineering)&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 优化 / Skill 生成 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.66</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 把 LLM 的 context 当作<strong>演化的 playbook</strong> —— 生成 / 反思 / 策展三阶段防止 context 崩溃 + 保留细节知识。<strong>+10.6% 智能体任务 / +8.6% 金融任务</strong>。</p><p><strong>来源</strong>:</p><ul><li>学术研究（Stanford + 多家合作）</li><li>ICLR 2026 接收</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2510.04618" target="_blank" rel="noreferrer">arXiv 2510.04618</a></li><li>标题：<em>Agentic Context Engineering: Evolving Contexts for Self-Improving Language Models</em></li><li>作者：Qizheng Zhang, Changran Hu, Shubhangi Upasani, ... James Zou, Kunle Olukotun（共 13 人）</li><li>提交：2025-10-06；最新版：2026-03-29（v3）</li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="三阶段模块化流水线" tabindex="-1">三阶段模块化流水线 <a class="header-anchor" href="#三阶段模块化流水线" aria-label="Permalink to &quot;三阶段模块化流水线&quot;">​</a></h3><ol><li><strong>Generation（生成）</strong> — 基于当前 context 产出 trajectory</li><li><strong>Reflection（反思）</strong> — 提取该次执行中的可复用经验</li><li><strong>Curation（策展）</strong> — 把经验增量地写回 context（不覆盖也不爆炸）</li></ol><h3 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h3><p>不是无脑追加（会爆炸），也不是覆写（会丢细节），而是<strong>结构化、增量更新</strong>的 context 演化。Context 被视为持续生长的 <strong>playbook</strong>。</p><h3 id="实证结果" tabindex="-1">实证结果 <a class="header-anchor" href="#实证结果" aria-label="Permalink to &quot;实证结果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任务</th><th>提升</th></tr></thead><tbody><tr><td><strong>智能体任务</strong></td><td><strong>+10.6%</strong></td></tr><tr><td><strong>金融任务</strong></td><td><strong>+8.6%</strong></td></tr></tbody></table><p>无需标注数据，纯靠 reflection 自监督。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="为什么对-skills-重要" tabindex="-1">为什么对 Skills 重要 <a class="header-anchor" href="#为什么对-skills-重要" aria-label="Permalink to &quot;为什么对 Skills 重要&quot;">​</a></h3><p>ACE 提出的方法直接适用于 Skill 演化：把 Skill body 当作 playbook，用生成 / 反思 / 策展循环演化它。这是 2026 Q1 大量 Skill 优化论文的方法论基础。</p><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>论文未直接使用 &quot;Skill&quot; 一词，需要类比迁移到 Skill 场景</li><li>Reflection 质量依赖 LLM 自身能力上限</li><li>与传统的 GEPA / DSPy 相比偏向 context engineering 而非 prompt optimization</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.65</td><td>ICLR 2026 接收 + 3 个版本迭代</td></tr><tr><td>创新性</td><td>0.85</td><td>&quot;context as playbook&quot;是范式级抽象</td></tr><tr><td>落地程度</td><td>0.50</td><td>学术 + 部分商业实现（kayba.ai 等）</td></tr><tr><td>生态活跃度</td><td>0.65</td><td>被 2026 Q1 工作大量引用</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.66</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2510.04618" target="_blank" rel="noreferrer">ACE 论文 (arXiv 2510.04618)</a></li></ul>',31)])])}const b=a(n,[["render",l]]);export{u as __pageData,b as default};
